[ExtensionOf(tableStr(VendInvoiceJour))]
Final class ETG_VendInvoiceJour_Extension
{
}

Method.Source:
/// <summary>
/// This method initialize fields from table - VendInvoiceJour
/// </summary>
/// <param name = "_vendInvoiceInfoTable">VendInvoiceInfoTable _vendInvoiceInfoTable</param>
public void initFromVendInvoiceInfoTable(VendInvoiceInfoTable _vendInvoiceInfoTable)
{
    next initFromVendInvoiceInfoTable(_vendInvoiceInfoTable);
    this.ETG_BLnumber   = _vendInvoiceInfoTable.ETG_BLnumber;
    this.ETG_BLDate     = _vendInvoiceInfoTable.ETG_BLDate;
    //NS, TermoNumberTracking, 28052024, DLT. 
    //Populate Termo number from pending invoice to purchase order invoice journal 
    this.ETGTERMONumber = _vendInvoiceInfoTable.ETGTERMONumber;
    //NE, TermoNumberTracking, 28052024, DLT

    if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes && _vendInvoiceInfoTable.ETGDocumentDate)
    {
        this.DocumentDate = _vendInvoiceInfoTable.ETGDocumentDate;
    }

    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
        PurchTable  purchtableloc = PurchTable::find(_vendInvoiceInfoTable.PurchId);

        this.ETGCrDrNoteCreated =purchtableloc.ETGCrDrNoteCreated;
        this.ETGJournalNum = purchtableloc.ETGJournalNum;
        this.ETGCrDrJrnAmt =purchtableloc.ETGCrDrJrnAmt;
    }
}
